INSERT INTO applicant_faq (id, question, answer, category, keywords)
VALUES
('60000000-0000-0000-0000-000000000001', 'Какие документы нужны для поступления?', 'Для поступления нужны паспорт, документ об образовании, СНИЛС при наличии, фотографии и заявление. Точный список уточняйте в приемной комиссии.', 'documents', '["документы","паспорт","снилс","поступление"]'),
('60000000-0000-0000-0000-000000000002', 'Когда заканчивается прием документов?', 'Прием документов на очную форму обычно завершается в конце июля. Актуальные даты публикуются в разделе приемной комиссии.', 'deadlines', '["сроки","дедлайн","прием документов"]'),
('60000000-0000-0000-0000-000000000003', 'Где находится приемная комиссия?', 'Приемная комиссия находится в корпусе A на первом этаже, кабинет A-101 рядом с главным входом.', 'contacts', '["приемная комиссия","адрес","где находится"]'),
('60000000-0000-0000-0000-000000000004', 'Какие есть направления подготовки?', 'Доступны направления по ИТ, экономике, педагогике, инженерным и гуманитарным программам. Полный список есть на сайте университета.', 'programs', '["направления","специальности","программы"]'),
('60000000-0000-0000-0000-000000000005', 'Можно ли подать документы онлайн?', 'Да, документы можно подать онлайн через личный кабинет абитуриента или через Госуслуги, если направление поддерживает электронную подачу.', 'online', '["онлайн","подать","госуслуги"]')
